use crate::registry::DynModelDefinition;
use crate::DynBackendKind;
use anyhow::Result;
use block_core::param::{
    float_parameter, required_f32, ModelParameterSchema, ParameterSet, ParameterUnit,
};
use block_core::{AudioChannelLayout, BlockProcessor, ModelAudioMode, MonoProcessor, StereoProcessor};

pub const MODEL_ID: &str = "lv2_mod_caps_spice";
pub const DISPLAY_NAME: &str = "C* Spice";
const BRAND: &str = "caps";

const PLUGIN_URI: &str = "http://moddevices.com/plugins/caps/Spice";
const PLUGIN_DIR: &str = "mod-caps-Spice";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "Spice.dylib.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "Spice.dylib.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "Spice.dylib.dll";

// Port indices (from TTL)
const PORT_CTRL_LOF: usize = 0;
const PORT_CTRL_LOCOMP: usize = 1;
const PORT_CTRL_LOGAIN: usize = 2;
const PORT_CTRL_HIF: usize = 3;
const PORT_CTRL_HIGAIN: usize = 4;
const PORT_AUDIO_IN_IN: usize = 5;
const PORT_AUDIO_OUT_OUT: usize = 6;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_DYNAMICS.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::DualMono,
        parameters: vec![
            float_parameter("lof", "Low Frequency", None, Some(225.0), 50.0, 400.0, 1.0, ParameterUnit::Hertz),
            float_parameter("locomp", "Low Compression", None, Some(0.5), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("logain", "Low Gain", None, Some(0.25), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("hif", "High Frequency", None, Some(1350.0), 400.0, 5000.0, 10.0, ParameterUnit::Hertz),
            float_parameter("higain", "High Gain", None, Some(0.25), 0.0, 1.0, 0.01, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let lof = required_f32(params, "lof").map_err(anyhow::Error::msg)?;
    let locomp = required_f32(params, "locomp").map_err(anyhow::Error::msg)?;
    let logain = required_f32(params, "logain").map_err(anyhow::Error::msg)?;
    let hif = required_f32(params, "hif").map_err(anyhow::Error::msg)?;
    let higain = required_f32(params, "higain").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_LOF, lof),
        (PORT_CTRL_LOCOMP, locomp),
        (PORT_CTRL_LOGAIN, logain),
        (PORT_CTRL_HIF, hif),
        (PORT_CTRL_HIGAIN, higain),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: DynModelDefinition = DynModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: DynBackendKind::Lv2, schema, build,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};
